sql:
SELECT SUM(payment_amount) as total_amount
FROM violation_fine_payments
WHERE payment_method = 'credit card' AND payment_date BETWEEN '2020-01-01' AND '2020-12-31';

SELECT department, COUNT(*) AS number_of_officers
FROM officers
GROUP BY department;

external_knowledge:
Guardians of the law: Refers to police officers;
Casting the longest shadow: Metaphorically means issuing the most violations;
The length of the shadow: Represents the number of violations issued by each officer.

sql:
SELECT violation_id, plate_id, plate_type, violation_code, vehicle_make, violation_description, officer_id, location_id, status
FROM violations
WHERE violation_id = 0 AND status = 'paid';

SELECT SUM(violation_code) 
FROM violations 
WHERE officer_id = 'Your_ID_Here';

SELECT plate_id
FROM violations
WHERE status = 'issued' AND violation_code IS NOT NULL;

SELECT violation_id, issue_date, violation_description
FROM violations
ORDER BY issue_date ASC;
